mapper.select:
SELECT a.* FROM (SELECT d.doc_status, d.type, d.doc_owner, d.doc_suffix, d.bus_id AS docId, d.doc_name, d.doc_size, d.upload_time AS uploadTime, d.lower_time AS lowerTime, d.recycle_status, d.is_deleted, CASE WHEN u.doc_id IS NOT NULL THEN 0 ELSE 1 END AS isAsh, CASE WHEN uu.doc_id IS NOT NULL THEN 0 ELSE 1 END AS isSelect FROM doc_bs_document d LEFT JOIN (SELECT DISTINCT doc_id FROM doc_bs_document_user WHERE is_deleted = 0 AND rel_id IN
#{item}
) u ON u.doc_id = d.bus_id LEFT JOIN (SELECT DISTINCT doc_id FROM doc_bs_document_user WHERE is_deleted = 0 AND permiss_type = 2 AND rel_id IN
#{item}
) uu ON uu.doc_id = d.bus_id ) a
JOIN (SELECT doc_id FROM doc_bs_tag_document WHERE tag_id IN
#{item}
) t ON t.doc_id = a.docId
WHERE a.is_deleted = 0 AND a.type = 1 AND a.recycle_status = 0
AND a.doc_status = #{docStatus}
AND a.doc_name LIKE '%' || #{docName} || '%'
AND a.uploadTime BETWEEN #{uploadTimeTo} AND #{uploadTimeDo}
AND a.lowerTime BETWEEN #{lowerTimeTo} AND #{lowerTimeDo}
ORDER BY a.uploadTime ASC
ORDER BY a.uploadTime DESC
ORDER BY a.lowerTime ASC
ORDER BY a.lowerTime DESC
ORDER BY a.lowerTime DESC
